import urllib.request
import urllib.parse
import sys

user_agent = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
referer = 'https://embed18.streamc.xyz/embed.php?hash=99f386254c018729b4e6a32ac08029f2'

segment_path_with_plus = "https://embed18.streamc."

# Test 1: Fetch with original URL (+ retained)
try:
    req1 = urllib.request.Request(segment_path_with_plus, headers={'User-Agent': user_agent, 'Referer': referer})
    res1 = urllib.request.urlopen(req1)
    print("Test 1 (Original +): Status", res1.status, "Length", len(res1.read()))
except Exception as e:
    print("Test 1 Failed:", e)

# Test 2: Fetch with space replaced URL
segment_path_with_space = segment_path_with_plus.replace("+", " ")
try:
    req2 = urllib.request.Request(segment_path_with_space, headers={'User-Agent': user_agent, 'Referer': referer})
    res2 = urllib.request.urlopen(req2)
    print("Test 2 (Replaced space): Status", res2.status, "Length", len(res2.read()))
except Exception as e:
    print("Test 2 Failed:", e)
